  "family": "Hofmann-Löffler-Freytag Reaction (Remote Functionalization)",
  "candidate": {
    "substrate_smiles": [
      "CCCCN(C)Cl"
    ],
    "product_smiles": [
      "C1CCCN1C"
    ],
    "optional_reagent_smiles": [
      "O",
      "[H+]"
    ],
    "rationale": "This is a classic and simple example of the Hofmann-Löffler-Freytag reaction. The substrate, N-chloro-N-methylbutylamine, undergoes a 1,5-hydrogen atom transfer via a nitrogen-centered radical under acidic conditions, followed by cyclization to form the product, N-methylpyrrolidine. This example clearly demonstrates the key remote C-H functionalization and pyrrolidine ring formation characteristic of the reaction family.",
    "collision_avoidance_note": "This example uses a simple acyclic N-chloroamine substrate, which is specific to the Hofmann-Löffler-Freytag reaction. It avoids complex structures, arenes, or other functional groups that could cause collisions with unrelated named reactions like the Hofmann rearrangement (amides), Hofmann elimination (quaternary ammonium salts), or general radical cyclizations."
  }
}
